    /**
     * @method
     * @name arkham#fetchCurrencies
     * @description fetches all available currencies on an exchange
     * @see https://arkm.com/docs#get/public/assets
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an associative dictionary of currencies
     */
    public java.util.concurrent.CompletableFuture<Object> fetchCurrencies(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object response = (this.v1PublicGetAssets(parameters)).join();
            //
            //    [
            //        {
            //            "symbol": "USDT",
            //            "name": "Tether",
            //            "imageUrl": "https://static.arkhamintelligence.com/tokens/tether.png",
            //            "stablecoin": true,
            //            "featuredPair": "BTC_USDT",
            //            "chains": [
            //                {
            //                    "symbol": "ETH",
            //                    "assetSymbol": "ETH",
            //                    "name": "Ethereum",
            //                    "type": "1",
            //                    "confirmations": "6",
            //                    "blockTime": "12000000"
            //                }
            //            ],
            //            "status": "listed",
            //            "minDeposit": "5",
            //            "minWithdrawal": "5",
            //            "withdrawalFee": "2"
            //        },
            //        ...
            //
            Object result = new java.util.HashMap<String, Object>() {{}};
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(response)); i++)
            {
                Object currency = Helpers.GetValue(response, i);
                Object id = this.safeString(currency, "symbol");
                Object code = this.safeCurrencyCode(id);
                Object networks = new java.util.HashMap<String, Object>() {{}};
                Object chains = this.safeList(currency, "chains", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(chains)); j++)
                {
                    Object chain = Helpers.GetValue(chains, j);
                    Object networkId = this.safeString(chain, "symbol");
                    Object network = this.networkIdToCode(networkId);
                    Helpers.addElementToObject(networks, network, new java.util.HashMap<String, Object>() {{
        put( "info", chain );
        put( "id", networkId );
        put( "network", network );
        put( "title", ArkhamCore.this.safeString(chain, "name") );
        put( "active", null );
        put( "deposit", null );
        put( "withdraw", null );
        put( "fee", null );
        put( "precision", null );
        put( "limits", new java.util.HashMap<String, Object>() {{
            put( "withdraw", new java.util.HashMap<String, Object>() {{
                put( "min", null );
                put( "max", null );
            }} );
        }} );
    }});
                }
                Helpers.addElementToObject(result, code, this.safeCurrencyStructure(new java.util.HashMap<String, Object>() {{
        put( "info", currency );
        put( "id", id );
        put( "code", code );
        put( "name", ArkhamCore.this.safeString(currency, "name") );
        put( "active", Helpers.isEqual(ArkhamCore.this.safeString(currency, "status"), "listed") );
        put( "deposit", null );
        put( "withdraw", null );
        put( "fee", ArkhamCore.this.safeNumber(currency, "withdrawalFee") );
        put( "precision", null );
        put( "limits", new java.util.HashMap<String, Object>() {{
            put( "amount", new java.util.HashMap<String, Object>() {{
                put( "min", null );
                put( "max", null );
            }} );
            put( "withdraw", new java.util.HashMap<String, Object>() {{
                put( "min", ArkhamCore.this.safeNumber(currency, "minWithdrawal") );
                put( "max", null );
            }} );
            put( "deposit", new java.util.HashMap<String, Object>() {{
                put( "min", ArkhamCore.this.safeNumber(currency, "minDeposit") );
                put( "max", null );
            }} );
        }} );
        put( "type", "crypto" );
        put( "networks", networks );
    }}));
            }
            return result;
        });

    }

