    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades
        //
        //        {
        //            "symbol": "BTC_USDT_PERP",
        //            "revisionId": "1130514101",
        //            "size": "0.01668",
        //            "price": "116309.57",
        //            "takerSide": "sell",
        //            "time": "1753439710374047"
        //        }
        //
        // fetchMyTrades
        //
        //        {
        //            "symbol": "SOL_USDT",
        //            "revisionId": "891839406",
        //            "size": "0.042",
        //            "price": "185.06",
        //            "takerSide": "sell",
        //            "time": "1753773952039342",
        //            "orderId": "3717304929194",
        //            "userSide": "sell",
        //            "quoteFee": "0.00777252",
        //            "arkmFee": "0",
        //            "clientOrderId": ""
        //        }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(trade, "symbol");
        market = this.safeMarket(marketId, market);
        Object timestamp = this.safeIntegerProduct(trade, "time", 0.001);
        Object quoteFee = this.safeNumber(trade, "quoteFee");
        Object arkmFee = this.safeNumber(trade, "arkmFee");
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(quoteFee, null)))
        {
            final Object finalQuoteFee = quoteFee;
            final Object finalMarket = market;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalQuoteFee );
                put( "currency", Helpers.GetValue(finalMarket, "quote") );
            }};
        } else if (Helpers.isTrue(!Helpers.isEqual(arkmFee, null)))
        {
            final Object finalArkmFee = arkmFee;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalArkmFee );
                put( "currency", "ARKM" );
            }};
        }
        final Object finalMarket_2 = market;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", ArkhamCore.this.safeString(trade, "revisionId") );
            put( "timestamp", timestamp );
            put( "datetime", ArkhamCore.this.iso8601(timestamp) );
            put( "symbol", Helpers.GetValue(finalMarket_2, "symbol") );
            put( "type", null );
            put( "side", ArkhamCore.this.safeString2(trade, "userSide", "takerSide") );
            put( "takerOrMaker", null );
            put( "price", ArkhamCore.this.safeString(trade, "price") );
            put( "amount", ArkhamCore.this.safeString(trade, "size") );
            put( "cost", null );
            put( "fee", finalFee );
            put( "order", ArkhamCore.this.safeString(trade, "orderId") );
        }}, market);
    }

