    /**
     * @method
     * @name arkham#cancelOrder
     * @description cancels an open order
     * @see https://arkm.com/docs#post/orders/cancel
     * @param {string} id order id
     * @param {string} symbol unified symbol of the market the order was made in
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} An [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> cancelOrder(Object id, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            Object isTriggerOrder = this.safeBool(parameters, "trigger");
            parameters = this.omit(parameters, "trigger");
            Object response = null;
            Object request = new java.util.HashMap<String, Object>() {{}};
            Object clientOrderId = this.safeInteger(parameters, "clientOrderId");
            if (Helpers.isTrue(!Helpers.isEqual(clientOrderId, null)))
            {
                parameters = this.omit(parameters, "clientOrderId");
                Helpers.addElementToObject(request, "clientOrderId", clientOrderId);
            } else
            {
                if (Helpers.isTrue(isTriggerOrder))
                {
                    Helpers.addElementToObject(request, "triggerOrderId", Helpers.parseInt(id));
                } else
                {
                    Helpers.addElementToObject(request, "orderId", Helpers.parseInt(id));
                }
            }
            if (Helpers.isTrue(isTriggerOrder))
            {
                if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
                {
                    throw new ArgumentsRequired((String)Helpers.add(this.id, " cancelOrder() requires a symbol argument for trigger orders")) ;
                }
                Object market = this.market(symbol);
                Helpers.addElementToObject(request, "symbol", Helpers.GetValue(market, "id"));
                response = (this.v1PrivatePostTriggerOrdersCancel(this.extend(request, parameters))).join();
            } else
            {
                response = (this.v1PrivatePostOrdersCancel(this.extend(request, parameters))).join();
            }
            //
            // {"orderId":3691703758327}
            //
            return this.parseOrder(response);
        });

    }

