    /**
     * @method
     * @name arkham#fetchDepositAddress
     * @description fetch the deposit address for a currency associated with this account
     * @see https://arkm.com/docs#get/account/deposit/addresses
     * @param {string} code unified currency code
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [address structure]{@link https://docs.ccxt.com/?id=address-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchDepositAddress(Object code, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object currency = this.currency(code);
            Object networkCodeAndParams = this.handleNetworkCodeAndParams(parameters);
            Object networkCode = Helpers.GetValue(networkCodeAndParams, 0);
            Object indexedAddresses = (this.fetchDepositAddressesByNetwork(code, parameters)).join();
            Object selectedNetworkCode = this.selectNetworkCodeFromUnifiedNetworks(Helpers.GetValue(currency, "code"), networkCode, indexedAddresses);
            Object address = this.safeDict(indexedAddresses, selectedNetworkCode);
            if (Helpers.isTrue(Helpers.isEqual(address, null)))
            {
                throw new InvalidAddress((String)Helpers.add(Helpers.add(this.id, " fetchDepositAddress() could not find a deposit address for "), code)) ;
            }
            return address;
        });

    }

