    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        //        {
        //            "id": "238644",
        //            "symbol": "SOL",
        //            "amount": "0.104",
        //            "time": "1753436404000000",
        //            "confirmed": true,
        //            "transactionHash": "1DRxbbyePTsMuB82SDf2fG5gLXH5iYnY8TQDstDPLULpLtjMJtF1ug1T4Mf8B6DSb8fp2sb5YtdbyqieZ2tkE1Ve",
        //            "chain": "Solana",
        //            "depositAddress": "12NauJ26TUT9aYkpId7YdePJJDRMGbAsEMVoTVUvBErV",
        //            "price": "180.322010164"
        //        }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object address = this.safeString(transaction, "depositAddress");
        Object timestamp = this.safeIntegerProduct(transaction, "time", 0.001);
        Object confirmd = this.safeBool(transaction, "confirmed");
        Object status = null;
        if (Helpers.isTrue(confirmd))
        {
            status = "ok";
        }
        Object currencyId = this.safeString(transaction, "symbol");
        Object code = this.safeCurrencyCode(currencyId, currency);
        final Object finalStatus = status;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", ArkhamCore.this.safeString(transaction, "id") );
            put( "txid", ArkhamCore.this.safeString(transaction, "transactionHash") );
            put( "type", null );
            put( "currency", code );
            put( "network", ArkhamCore.this.networkIdToCode(ArkhamCore.this.safeString(transaction, "chain")) );
            put( "amount", ArkhamCore.this.safeNumber(transaction, "amount") );
            put( "status", finalStatus );
            put( "timestamp", timestamp );
            put( "datetime", ArkhamCore.this.iso8601(timestamp) );
            put( "address", address );
            put( "addressFrom", null );
            put( "addressTo", address );
            put( "tag", null );
            put( "tagFrom", null );
            put( "tagTo", null );
            put( "updated", null );
            put( "comment", null );
            put( "fee", null );
            put( "internal", false );
        }};
    }

    /**
     * @method
     * @name arkham#fetchTradingFees
     * @description fetch the trading fees for multiple markets
     * @see https://arkm.com/docs#get/account/fees
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.subType] "linear" or "inverse"
     * @returns {object} a dictionary of [fee structures]{@link https://docs.ccxt.com/?id=fee-structure} indexed by market symbols
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTradingFees(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object response = (this.v1PrivateGetAccountFees(parameters)).join();
            //
            // {
            //   "perpMakerFee": "1.23",
            //   "perpTakerFee": "1.23",
            //   "spotMakerFee": "1.23",
            //   "spotTakerFee": "1.23"
            // }
            //
            Object symbols = Helpers.objectKeys(this.markets);
            Object result = new java.util.HashMap<String, Object>() {{}};
            Object spotMaker = this.safeNumber(response, "spotMakerFee");
            Object spotTaker = this.safeNumber(response, "spotTakerFee");
            Object perpMaker = this.safeNumber(response, "perpMakerFee");
            Object perpTaker = this.safeNumber(response, "perpTakerFee");
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(symbols)); i++)
            {
                Object symbol = Helpers.GetValue(symbols, i);
                Object market = Helpers.GetValue(this.markets, symbol);
                Helpers.addElementToObject(result, symbol, new java.util.HashMap<String, Object>() {{
        put( "info", response );
        put( "symbol", symbol );
    }});
                if (Helpers.isTrue(Helpers.GetValue(market, "spot")))
                {
                    Helpers.addElementToObject(Helpers.GetValue(result, symbol), "maker", spotMaker);
                    Helpers.addElementToObject(Helpers.GetValue(result, symbol), "taker", spotTaker);
                } else if (Helpers.isTrue(Helpers.isTrue(Helpers.GetValue(market, "swap")) || Helpers.isTrue(Helpers.GetValue(market, "future"))))
                {
                    Helpers.addElementToObject(Helpers.GetValue(result, symbol), "maker", perpMaker);
                    Helpers.addElementToObject(Helpers.GetValue(result, symbol), "taker", perpTaker);
                }
            }
            return result;
        });

    }

