    public Object parsePosition(Object position, Object... optionalArgs)
    {
        //
        //        {
        //            "subaccountId": "0",
        //            "symbol": "SOL_USDT_PERP",
        //            "base": "0.037",                             // negative for short position
        //            "quote": "-6.44614",                         // negative for long position
        //            "openBuySize": "0",
        //            "openSellSize": "0",
        //            "openBuyNotional": "0",
        //            "openSellNotional": "0",
        //            "lastUpdateReason": "orderFill",
        //            "lastUpdateTime": "1753903829389966",
        //            "lastUpdateId": "250434684",
        //            "lastUpdateBaseDelta": "0.037",
        //            "lastUpdateQuoteDelta": "-6.44614",
        //            "breakEvenPrice": "174.22",
        //            "markPrice": "174.33",
        //            "value": "6.45021",
        //            "pnl": "0.00407",
        //            "initialMargin": "0.645021",
        //            "maintenanceMargin": "0.3870126",
        //            "averageEntryPrice": "174.22"
        //        }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object base = this.safeString(position, "base");
        Object baseAbs = Precise.stringAbs(base);
        Object isLong = Precise.stringGe(base, "0");
        Object side = ((Helpers.isTrue(isLong))) ? "long" : "short";
        Object marketId = this.safeString(position, "symbol");
        Object notional = this.safeString(position, "value");
        return this.safePosition(new java.util.HashMap<String, Object>() {{
            put( "info", position );
            put( "id", null );
            put( "symbol", ArkhamCore.this.safeSymbol(marketId, market) );
            put( "notional", ArkhamCore.this.parseNumber(Precise.stringAbs(notional)) );
            put( "marginMode", null );
            put( "liquidationPrice", null );
            put( "entryPrice", ArkhamCore.this.safeNumber(position, "averageEntryPrice") );
            put( "unrealizedPnl", ArkhamCore.this.safeNumber(position, "pnl") );
            put( "realizedPnl", null );
            put( "percentage", null );
            put( "contracts", ArkhamCore.this.parseNumber(baseAbs) );
            put( "contractSize", null );
            put( "markPrice", ArkhamCore.this.safeNumber(position, "markPrice") );
            put( "lastPrice", null );
            put( "side", side );
            put( "hedged", null );
            put( "timestamp", null );
            put( "datetime", null );
            put( "lastUpdateTimestamp", ArkhamCore.this.safeInteger(position, "lastUpdateTime") );
            put( "maintenanceMargin", ArkhamCore.this.safeNumber(position, "maintenanceMargin") );
            put( "maintenanceMarginPercentage", null );
            put( "collateral", null );
            put( "initialMargin", ArkhamCore.this.safeNumber(position, "initialMargin") );
            put( "initialMarginPercentage", null );
            put( "leverage", null );
            put( "marginRatio", null );
            put( "stopLossPrice", null );
            put( "takeProfitPrice", null );
        }});
    }

    /**
     * @method
     * @name arkkm#withdraw
     * @description make a withdrawal
     * @see https://arkm.com/docs#post/account/withdraw
     * @see https://arkm.com/docs#get/account/withdrawal/addresses
     * @param {string} code unified currency code
     * @param {float} amount the amount to withdraw
     * @param {string} address the address to withdraw to
     * @param {string} tag
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [transaction structure]{@link https://docs.ccxt.com/?id=transaction-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> withdraw(Object code, Object amount, Object address2, Object... optionalArgs)
    {
        final Object address3 = address2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object address = address3;
            Object tag = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            var tagparametersVariable = this.handleWithdrawTagAndParams(tag, parameters);
            tag = ((java.util.List<Object>) tagparametersVariable).get(0);
            parameters = ((java.util.List<Object>) tagparametersVariable).get(1);
            (this.loadMarkets()).join();
            Object withdrawalAddresses = (this.v1PrivateGetAccountWithdrawalAddresses()).join();
            //
            //    [
            //        {
            //            "id": "12345",
            //            "chain": "ETH",
            //            "address": "0x743f79D65EA07AA222F4a83c10dee4210A920a6e",
            //            "label": "my_binance",
            //            "createdAt": "1753905200074355",
            //            "updatedAt": "1753905213464278",
            //            "confirmed": true
            //        }
            //    ]
            //
            Object currency = this.currency(code);
            final Object finalParameters = parameters;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(currency, "id") );
                put( "amount", ArkhamCore.this.currencyToPrecision(code, amount) );
                put( "subaccountId", ArkhamCore.this.safeInteger(finalParameters, "subAccountId", 0) );
            }};
            Object networkCode = null;
            var networkCodeparametersVariable = this.handleNetworkCodeAndParams(parameters);
            networkCode = ((java.util.List<Object>) networkCodeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) networkCodeparametersVariable).get(1);
            if (Helpers.isTrue(Helpers.isEqual(networkCode, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " withdraw() requires a \"network\" param")) ;
            }
            Object indexedList = this.groupBy(withdrawalAddresses, "address");
            if (!Helpers.isTrue((Helpers.inOp(indexedList, address))))
            {
                throw new InvalidAddress((String)Helpers.add(this.id, " withdraw() requires an address that has been previously added to the whitelisted addresses")) ;
            }
            Object withdrawalObjects = Helpers.GetValue(indexedList, address);
            Object foundWithdrawalObject = null;
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(withdrawalObjects)); i++)
            {
                Object withdrawalObject = Helpers.GetValue(withdrawalObjects, i);
                if (Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(withdrawalObject, "chain"), networkCode)))
                {
                    foundWithdrawalObject = withdrawalObject;
                    break;
                }
            }
            if (Helpers.isTrue(Helpers.isEqual(foundWithdrawalObject, null)))
            {
                throw new InvalidAddress((String)Helpers.add(Helpers.add(Helpers.add(Helpers.add(this.id, " withdraw() can not find whitelisted withdrawal address for "), address), " with network "), networkCode)) ;
            }
            Helpers.addElementToObject(request, "addressId", this.safeInteger(foundWithdrawalObject, "id"));
            Object response = (this.v1PrivatePostAccountWithdraw(this.extend(request, parameters))).join();
            //
            // response is a weird string like:
            //
            //    "1234709779980\\n"
            //
            Object responseString = Helpers.replace((String)response, (String)"\n", (String)"");
            Object data = new java.util.HashMap<String, Object>() {{
                put( "id", responseString );
            }};
            return this.parseTransaction(data, currency);
        });

    }

